run.command:
sh -c 'id -u cs16 >/dev/null 2>&1 || useradd -m cs16 || adduser -D cs16; mkdir -p /home/cs16/.steam/sdk32; if [ -f ./linux32/steamclient.so ]; then cp ./linux32/steamclient.so /home/cs16/.steam/sdk32/; elif [ -f /root/steamcmd/linux32/steamclient.so ]; then cp /root/steamcmd/linux32/steamclient.so /home/cs16/.steam/sdk32/; fi; chown -R cs16:cs16 . /home/cs16/.steam; cat > cstrike/server.cfg << EOF
hostname "${hostname}"
rcon_password "${rcon_password}"
maxplayers ${players}
mp_timelimit ${timelimit}
mp_roundtime ${roundtime}
mp_freezetime ${freezetime}
mp_startmoney ${startmoney}
sv_lan ${sv_lan}
EOF
chown cs16:cs16 cstrike/server.cfg; exec runuser -u cs16 -- box64 ./hlds_linux -game cstrike +ip 0.0.0.0 -console +maxplayers ${players} +map ${map} +port ${port} +exec server.cfg'
